INSERT INTO `news_article` VALUES (1,'Năm 2026 tiếp tục ưu tiên không gian sống gọn, ấm và dễ ứng dụng. Các thiết kế nổi bật tập trung vào bảng màu trung tính, chất liệu gỗ sáng và những món nội thất có tỷ lệ vừa phải cho căn hộ thành thị. Đây là hướng đi phù hợp với nhu cầu sống linh hoạt, thẩm mỹ nhưng vẫn chú trọng công năng hằng ngày.','https://images.unsplash.com/photo-1505693416388-ac5ce068fe85?auto=format&fit=crop&q=80&w=1200','Xu hướng nội thất 2026 cho căn hộ hiện đại','Xu hướng'),(2,'Một phòng khách cân đối nên bắt đầu từ tỷ lệ giữa sofa, bàn trà và thảm. Sofa nên là điểm tựa chính, bàn trà nhỏ hơn vừa đủ để tạo khoảng thở, còn thảm nên ôm trọn khu vực tiếp khách để liên kết tổng thể. Chọn cùng tông màu hoặc các sắc độ gần nhau sẽ giúp không gian gọn và cao cấp hơn.','https://images.unsplash.com/photo-1484154218962-a197022b5858?auto=format&fit=crop&q=80&w=1200','Cách phối sofa, bàn trà và thảm để phòng khách hài hòa','Mẹo bài trí'),(3,'Với phòng ngủ diện tích nhỏ, ưu tiên những mẫu giường có thiết kế thanh thoát, màu sáng và chiều cao hợp lý để không tạo cảm giác nặng nề. Tủ quần áo nên chọn dạng cánh lùa hoặc chiều sâu gọn để tiết kiệm diện tích sử dụng. Sự đồng bộ về vật liệu và màu sắc giữa giường, tab đầu giường và tủ sẽ giúp căn phòng trông rộng và dễ chịu hơn.','https://images.unsplash.com/photo-1505693416388-ac5ce068fe85?auto=format&fit=crop&q=80&w=1200','Bí quyết chọn giường ngủ và tủ quần áo cho phòng nhỏ','Không gian sống');
/*!40000 ALTER TABLE `news_article` ENABLE KEYS */;
UNLOCK TABLES;

